/**
 * Analytics data model definitions.
 *
 * These types represent aggregated analytics data derived from
 * orders and users. They are produced by the AnalyticsService
 * and consumed by dashboard views.
 */

import type { OrderStatus } from './order.js';

/**
 * A single data point in a time series.
 */
export interface TimeSeriesDataPoint {
  /** ISO date string (YYYY-MM-DD) representing the period */
  date: string;
  /** Aggregated value for this period */
  value: number;
}

/**
 * Time-series data for a named metric over a date range.
 */
export interface TimeSeriesResult {
  metric: string;
  startDate: string;
  endDate: string;
  dataPoints: TimeSeriesDataPoint[];
}

/**
 * Granularity for time-series aggregation.
 */
export type TimeGranularity = 'day' | 'week' | 'month';

/**
 * Summary of key order metrics.
 */
export interface OrderMetricSummary {
  totalOrders: number;
  totalRevenue: number;
  averageOrderValue: number;
  ordersByStatus: Record<OrderStatus, number>;
}

/**
 * Summary of key user metrics.
 */
export interface UserMetricSummary {
  totalUsers: number;
  usersByRole: Record<string, number>;
  newUsersInPeriod: number;
}

/**
 * Top product by quantity sold or revenue.
 */
export interface TopProduct {
  productId: string;
  name: string;
  totalQuantity: number;
  totalRevenue: number;
}

/**
 * Composed dashboard data combining multiple analytics summaries.
 */
export interface DashboardData {
  generatedAt: Date;
  periodStart: Date;
  periodEnd: Date;
  orderMetrics: OrderMetricSummary;
  userMetrics: UserMetricSummary;
  revenueTimeSeries: TimeSeriesResult;
  ordersTimeSeries: TimeSeriesResult;
  topProducts: TopProduct[];
}

/**
 * Analytics data aggregation service.
 *
 * Processes raw order and user data into analytics summaries for
 * the dashboard. Provides time-series aggregation, metric summaries,
 * and composed dashboard data.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture note: This service is read-only — it queries existing
 * data through repositories and produces aggregated views. It does
 * not modify any data or emit events.
 */

import type { Order } from '../models/order.js';
import type { OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';
import type {
  TimeSeriesDataPoint,
  TimeSeriesResult,
  TimeGranularity,
  OrderMetricSummary,
  UserMetricSummary,
  TopProduct,
  DashboardData,
} from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

const ALL_ORDER_STATUSES: OrderStatus[] = [
  'pending',
  'confirmed',
  'shipped',
  'delivered',
  'cancelled',
];

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Aggregate orders into a time series for a given metric.
   *
   * Supported metrics:
   * - "revenue": sum of order totals per period
   * - "orderCount": count of orders per period
   */
  getTimeSeries(
    metric: 'revenue' | 'orderCount',
    startDate: Date,
    endDate: Date,
    granularity: TimeGranularity = 'day',
  ): TimeSeriesResult {
    this.logger.info(
      `Generating time series: metric=${metric}, granularity=${granularity}`,
    );

    const orders = this.orderRepository.findAll();
    const filteredOrders = orders.filter(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    const buckets = this.buildTimeBuckets(startDate, endDate, granularity);

    for (const order of filteredOrders) {
      const bucketKey = this.getBucketKey(order.createdAt, granularity);
      const bucket = buckets.get(bucketKey);
      if (bucket) {
        if (metric === 'revenue') {
          bucket.value += order.total;
        } else {
          bucket.value += 1;
        }
      }
    }

    const dataPoints = Array.from(buckets.values());

    return {
      metric,
      startDate: startDate.toISOString().split('T')[0],
      endDate: endDate.toISOString().split('T')[0],
      dataPoints,
    };
  }

  /**
   * Compute summary metrics for orders, optionally filtered to a date range.
   */
  getOrderMetrics(startDate?: Date, endDate?: Date): OrderMetricSummary {
    this.logger.info('Computing order metric summary');

    let orders = this.orderRepository.findAll();

    if (startDate || endDate) {
      orders = orders.filter((order) => {
        if (startDate && order.createdAt < startDate) return false;
        if (endDate && order.createdAt > endDate) return false;
        return true;
      });
    }

    const totalOrders = orders.length;
    const totalRevenue = orders.reduce((sum, order) => sum + order.total, 0);
    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

    const ordersByStatus = {} as Record<OrderStatus, number>;
    for (const status of ALL_ORDER_STATUSES) {
      ordersByStatus[status] = 0;
    }
    for (const order of orders) {
      ordersByStatus[order.status] += 1;
    }

    return {
      totalOrders,
      totalRevenue,
      averageOrderValue,
      ordersByStatus,
    };
  }

  /**
   * Compute summary metrics for users, optionally counting new users in a period.
   */
  getUserMetrics(periodStart?: Date, periodEnd?: Date): UserMetricSummary {
    this.logger.info('Computing user metric summary');

    const users = this.userRepository.findAll();
    const totalUsers = users.length;

    const usersByRole: Record<string, number> = {};
    for (const user of users) {
      usersByRole[user.role] = (usersByRole[user.role] ?? 0) + 1;
    }

    let newUsersInPeriod = 0;
    if (periodStart || periodEnd) {
      newUsersInPeriod = users.filter((user) => {
        if (periodStart && user.createdAt < periodStart) return false;
        if (periodEnd && user.createdAt > periodEnd) return false;
        return true;
      }).length;
    }

    return {
      totalUsers,
      usersByRole,
      newUsersInPeriod,
    };
  }

  /**
   * Get the top products by revenue within a date range.
   */
  getTopProducts(
    startDate?: Date,
    endDate?: Date,
    limit: number = 10,
  ): TopProduct[] {
    this.logger.info(`Computing top ${limit} products`);

    let orders = this.orderRepository.findAll();

    if (startDate || endDate) {
      orders = orders.filter((order) => {
        if (startDate && order.createdAt < startDate) return false;
        if (endDate && order.createdAt > endDate) return false;
        return true;
      });
    }

    // Exclude cancelled orders from product rankings
    orders = orders.filter((order) => order.status !== 'cancelled');

    const productMap = new Map<
      string,
      { productId: string; name: string; totalQuantity: number; totalRevenue: number }
    >();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        if (existing) {
          existing.totalQuantity += item.quantity;
          existing.totalRevenue += item.quantity * item.unitPrice;
        } else {
          productMap.set(item.productId, {
            productId: item.productId,
            name: item.name,
            totalQuantity: item.quantity,
            totalRevenue: item.quantity * item.unitPrice,
          });
        }
      }
    }

    return Array.from(productMap.values())
      .sort((a, b) => b.totalRevenue - a.totalRevenue)
      .slice(0, limit);
  }

  /**
   * Compose a full dashboard data payload for a given date range.
   *
   * Combines order metrics, user metrics, time-series data, and
   * top products into a single response suitable for dashboard rendering.
   */
  getDashboardData(periodStart: Date, periodEnd: Date): DashboardData {
    this.logger.info('Composing dashboard data');

    const orderMetrics = this.getOrderMetrics(periodStart, periodEnd);
    const userMetrics = this.getUserMetrics(periodStart, periodEnd);
    const revenueTimeSeries = this.getTimeSeries(
      'revenue',
      periodStart,
      periodEnd,
      'day',
    );
    const ordersTimeSeries = this.getTimeSeries(
      'orderCount',
      periodStart,
      periodEnd,
      'day',
    );
    const topProducts = this.getTopProducts(periodStart, periodEnd);

    return {
      generatedAt: new Date(),
      periodStart,
      periodEnd,
      orderMetrics,
      userMetrics,
      revenueTimeSeries,
      ordersTimeSeries,
      topProducts,
    };
  }

  /**
   * Build a map of empty time buckets covering the date range.
   */
  private buildTimeBuckets(
    startDate: Date,
    endDate: Date,
    granularity: TimeGranularity,
  ): Map<string, TimeSeriesDataPoint> {
    const buckets = new Map<string, TimeSeriesDataPoint>();
    const current = new Date(startDate);

    while (current <= endDate) {
      const key = this.getBucketKey(current, granularity);
      if (!buckets.has(key)) {
        buckets.set(key, { date: key, value: 0 });
      }
      this.advanceDate(current, granularity);
    }

    return buckets;
  }

  /**
   * Get the bucket key for a date given a granularity.
   */
  private getBucketKey(date: Date, granularity: TimeGranularity): string {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');

    switch (granularity) {
      case 'day':
        return `${year}-${month}-${day}`;
      case 'week': {
        // Use the Monday of the week as the bucket key
        const d = new Date(date);
        const dayOfWeek = d.getDay();
        const diff = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
        d.setDate(d.getDate() + diff);
        const wy = d.getFullYear();
        const wm = String(d.getMonth() + 1).padStart(2, '0');
        const wd = String(d.getDate()).padStart(2, '0');
        return `${wy}-${wm}-${wd}`;
      }
      case 'month':
        return `${year}-${month}-01`;
    }
  }

  /**
   * Advance a date by one unit of the given granularity.
   */
  private advanceDate(date: Date, granularity: TimeGranularity): void {
    switch (granularity) {
      case 'day':
        date.setDate(date.getDate() + 1);
        break;
      case 'week':
        date.setDate(date.getDate() + 7);
        break;
      case 'month':
        date.setMonth(date.getMonth() + 1);
        break;
    }
  }
}

